previewCss:
.darma-loader-uiverse-retro-monitor-progress .darma-loader-uiverse-retro-monitor-progress__box {
background-color: rgb(84, 84, 84);
width: 220px;
height: 220px;
padding: 20px;
border-radius: 20px;
border: 5px solid gray;
position: relative;
overflow: hidden;
box-shadow: 3px 4px 5px rgb(193, 193, 193);
}

.darma-loader-uiverse-retro-monitor-progress .darma-loader-uiverse-retro-monitor-progress__box .darma-loader-uiverse-retro-monitor-progress__screen {
position: absolute;
top: 50%;
left: 50%;
transform: translate(-50%, -50%);
background-color: black;
width: calc(100% - 40px);
height: calc(100% - 40px);
border-radius: 10px;
padding: 10px;
overflow: hidden;
}

.darma-loader-uiverse-retro-monitor-progress__screen .darma-loader-uiverse-retro-monitor-progress__lightray-limit {
position: absolute;
top: 50%;
left: 50%;
transform: translate(-50%, -50%);
width: calc(100% - 20px);
height: calc(100% - 20px);
overflow: hidden;
border-radius: 10px;
}

.darma-loader-uiverse-retro-monitor-progress__screen .darma-loader-uiverse-retro-monitor-progress__lightray {
position: absolute;
left: 0;
top: 0;
transform: translate(-50%, -50%);
width: 250%;
height: 250%;
background-image: radial-gradient(#ffffffa1, transparent, transparent);
border-radius: 10px 10px 0 0;
}

.darma-loader-uiverse-retro-monitor-progress__screen .darma-loader-uiverse-retro-monitor-progress__box {
position: absolute;
left: 50%;
top: 50%;
transform: translate(-50%, -50%);
width: 70%;
padding: 5px;
border: 5px solid #fff;
}

.darma-loader-uiverse-retro-monitor-progress__screen .darma-loader-uiverse-retro-monitor-progress__box .darma-loader-uiverse-retro-monitor-progress__progress {
width: 0;
height: 5px;
background-color: #fff;
animation: darma-loader-uiverse-retro-monitor-progress-progress 5s infinite;
}

.darma-loader-uiverse-retro-monitor-progress__top-side {
position: absolute;
width: 100%;
height: 100%;
top: -55px;
left: 50%;
transform: translate(-50%, -50%) rotate(45deg);
box-shadow: 10px 10px 10px #1f1f1f8a;
background-color: #1f1f1f8a;
}

.darma-loader-uiverse-retro-monitor-progress__bottom-side {
position: absolute;
width: 100%;
height: 100%;
top: calc(100% + 60px);
left: 50%;
transform: translate(-50%, -50%) rotate(45deg);
box-shadow: -10px -10px 10px #a5a5a5;
background-color: #a5a5a5;
}

@keyframes darma-loader-uiverse-retro-monitor-progress-progress {
from {
width: 0;
}
to {
width: 100%;
}
}

